import org.junit.jupiter.api.Test;

class TypeAdaptersTest {

  static class BaseClass {}
  static class SubClass extends BaseClass {}

  @Test
  void newFactoryForMultipleTypes_returnsAdapterForBaseAndSubTypes_andNullOtherwise() {
    @SuppressWarnings("unchecked")
    TypeAdapter<BaseClass> mockAdapter = mock(TypeAdapter.class);

    TypeAdapterFactory factory = TypeAdapters.newFactoryForMultipleTypes(BaseClass.class, SubClass.class, mockAdapter);

    Gson gson = mock(Gson.class);

    // TypeToken for base class
    TypeToken<BaseClass> baseTypeToken = TypeToken.get(BaseClass.class);
    // TypeToken for sub class
    TypeToken<SubClass> subTypeToken = TypeToken.get(SubClass.class);
    // TypeToken for unrelated class
    TypeToken<String> stringTypeToken = TypeToken.get(String.class);

    // create() should return the adapter for base class
    TypeAdapter<BaseClass> adapterForBase = factory.create(gson, baseTypeToken);
    assertSame(mockAdapter, adapterForBase);

    // create() should return the adapter for sub class
    @SuppressWarnings("unchecked")
    TypeAdapter<SubClass> adapterForSub = factory.create(gson, subTypeToken);
    assertSame(mockAdapter, adapterForSub);

    // create() should return null for unrelated class
    TypeAdapter<String> adapterForString = factory.create(gson, stringTypeToken);
    assertNull(adapterForString);

    // toString() returns expected string
    String expectedToString = "Factory[type=" + BaseClass.class.getName()
        + "+" + SubClass.class.getName() + ",adapter=" + mockAdapter + "]";
    assertEquals(expectedToString, factory.toString());
  }
}
